using ICSharpCode.WpfDesign;namespace BgCommon.UI.Designer.Serialization{    /// <summary>    /// 序列化服务    /// </summary>    public class SerializationService    {        private readonly SerializationManager _serializationManager;                /// <summary>        /// 序列化管理器        /// </summary>        public SerializationManager SerializationManager => _serializationManager;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public SerializationService(DesignContext context)        {            _serializationManager = new SerializationManager(context);        }    }}